// Extract and validate webhook payload
const payload = $input.item.json;

// Validation
if (!payload.transaction_id || !payload.receipt_number) {
  throw new Error('Missing required fields: transaction_id or receipt_number');
}

if (payload.calendar_accepted === true) {
  throw new Error('Calendar transactions do not generate fiscal receipts');
}

if (payload.amount < 6) {
  throw new Error('Amount must be >= 6€ for fiscal receipt');
}

// Return clean data structure
return {
  transactionId: payload.transaction_id,
  receiptNumber: payload.receipt_number,
  amount: parseFloat(payload.amount),
  paymentMethod: payload.payment_method,
  createdAt: payload.created_at,
  donor: {
    email: payload.donor.email,
    name: payload.donor.name || `${payload.donor.first_name || ''} ${payload.donor.last_name || ''}`.trim(),
    firstName: payload.donor.first_name,
    lastName: payload.donor.last_name,
    address: payload.donor.address,
    zip: payload.donor.zip,
    city: payload.donor.city
  },
  receiptUrl: payload.receipt_url,
  userId: payload.user_id,
  tourneeId: payload.tournee_id
};

// Get data from previous nodes
const extractedData = $('Extract & Validate Data').item.json;
const transaction = $input.item.json[0];

if (!transaction) {
  throw new Error('Transaction not found in Supabase');
}

// Calculate tax reduction (66%)
const taxReduction = (extractedData.amount * 0.66).toFixed(2);

// Format date
const date = new Date(extractedData.createdAt);
const formattedDate = date.toLocaleDateString('fr-FR', {
  year: 'numeric',
  month: 'long',
  day: 'numeric'
});

// Build HTML receipt
const html = `<!DOCTYPE html>
<html lang="fr">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Reçu Fiscal - ${extractedData.receiptNumber}</title>
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    body {
      font-family: 'Arial', sans-serif;
      padding: 60px 40px;
      color: #333;
      line-height: 1.6;
    }
    .container {
      max-width: 800px;
      margin: 0 auto;
    }
    .header {
      text-align: center;
      margin-bottom: 50px;
      border-bottom: 3px solid #dc2626;
      padding-bottom: 30px;
    }
    .header h1 {
      color: #dc2626;
      font-size: 36px;
      margin-bottom: 10px;
      text-transform: uppercase;
      letter-spacing: 2px;
    }
    .receipt-number {
      font-size: 18px;
      color: #666;
      font-weight: bold;
    }
    .org-info {
      background-color: #f9fafb;
      padding: 25px;
      border-radius: 8px;
      margin-bottom: 30px;
      border-left: 4px solid #dc2626;
    }
    .org-info h2 {
      color: #dc2626;
      font-size: 20px;
      margin-bottom: 15px;
    }
    .org-info p {
      margin-bottom: 8px;
      font-size: 14px;
    }
    .donor-section {
      margin-bottom: 30px;
    }
    .donor-section h3 {
      color: #1f2937;
      font-size: 18px;
      margin-bottom: 15px;
      border-bottom: 2px solid #e5e7eb;
      padding-bottom: 8px;
    }
    .info-grid {
      display: grid;
      grid-template-columns: 200px 1fr;
      gap: 12px;
      margin-bottom: 20px;
    }
    .info-label {
      font-weight: bold;
      color: #4b5563;
    }
    .info-value {
      color: #1f2937;
    }
    .amount-box {
      background: linear-gradient(135deg, #dc2626 0%, #b91c1c 100%);
      color: white;
      padding: 25px;
      border-radius: 8px;
      margin: 30px 0;
      text-align: center;
    }
    .amount-box .label {
      font-size: 16px;
      margin-bottom: 10px;
      opacity: 0.9;
    }
    .amount-box .value {
      font-size: 42px;
      font-weight: bold;
      margin-bottom: 15px;
    }
    .tax-info {
      background-color: #fef2f2;
      border: 2px solid #dc2626;
      padding: 20px;
      border-radius: 8px;
      margin: 30px 0;
    }
    .tax-info h3 {
      color: #dc2626;
      margin-bottom: 15px;
      font-size: 18px;
    }
    .tax-info p {
      margin-bottom: 10px;
      font-size: 14px;
    }
    .tax-amount {
      font-size: 28px;
      font-weight: bold;
      color: #dc2626;
      margin-top: 15px;
    }
    .legal {
      background-color: #f9fafb;
      padding: 20px;
      border-radius: 8px;
      margin-top: 40px;
      font-size: 12px;
      color: #6b7280;
      line-height: 1.8;
    }
    .legal h4 {
      color: #374151;
      margin-bottom: 12px;
      font-size: 14px;
    }
    .footer {
      margin-top: 50px;
      padding-top: 30px;
      border-top: 2px solid #e5e7eb;
      text-align: center;
      color: #6b7280;
      font-size: 12px;
    }
    .signature-section {
      margin-top: 50px;
      text-align: right;
    }
    .signature-line {
      display: inline-block;
      border-top: 2px solid #333;
      padding-top: 10px;
      margin-top: 60px;
      min-width: 250px;
      text-align: center;
      font-size: 14px;
    }
  </style>
</head>
<body>
  <div class="container">
    <!-- Header -->
    <div class="header">
      <h1>Reçu Fiscal</h1>
      <p class="receipt-number">N° ${extractedData.receiptNumber}</p>
    </div>

    <!-- Organization Info -->
    <div class="org-info">
      <h2>Organisme Bénéficiaire</h2>
      <p><strong>Association des Sapeurs-Pompiers de Clermont</strong></p>
      <p>Association loi 1901 d'intérêt général</p>
      <p>Habilitation à recevoir des dons ouvrant droit à réduction d'impôt</p>
    </div>

    <!-- Donor Section -->
    <div class="donor-section">
      <h3>Informations du Donateur</h3>
      <div class="info-grid">
        <div class="info-label">Nom complet :</div>
        <div class="info-value">${extractedData.donor.name || 'Non renseigné'}</div>

        <div class="info-label">Adresse email :</div>
        <div class="info-value">${extractedData.donor.email}</div>

        ${extractedData.donor.address ? `
        <div class="info-label">Adresse :</div>
        <div class="info-value">${extractedData.donor.address}</div>
        ` : ''}

        ${extractedData.donor.zip && extractedData.donor.city ? `
        <div class="info-label">Ville :</div>
        <div class="info-value">${extractedData.donor.zip} ${extractedData.donor.city}</div>
        ` : ''}
      </div>
    </div>

    <!-- Donation Amount -->
    <div class="amount-box">
      <div class="label">Montant du Don</div>
      <div class="value">${extractedData.amount.toFixed(2)} €</div>
      <div class="label">Date : ${formattedDate}</div>
    </div>

    <!-- Transaction Details -->
    <div class="donor-section">
      <h3>Détails de la Transaction</h3>
      <div class="info-grid">
        <div class="info-label">Mode de paiement :</div>
        <div class="info-value">${extractedData.paymentMethod === 'card' ? 'Carte bancaire' : extractedData.paymentMethod === 'cash' ? 'Espèces' : extractedData.paymentMethod || 'Non renseigné'}</div>

        <div class="info-label">Date de la transaction :</div>
        <div class="info-value">${formattedDate}</div>
      </div>
    </div>

    <!-- Tax Reduction Info -->
    <div class="tax-info">
      <h3>🎯 Avantage Fiscal</h3>
      <p>Conformément à l'article 200 du Code Général des Impôts, ce don ouvre droit à une réduction d'impôt sur le revenu égale à <strong>66% du montant versé</strong>, dans la limite de 20% du revenu imposable.</p>
      <p>Pour ce don de <strong>${extractedData.amount.toFixed(2)} €</strong>, vous bénéficiez d'une réduction d'impôt de :</p>
      <div class="tax-amount">${taxReduction} €</div>
      <p style="margin-top: 15px; font-size: 13px; font-style: italic;">Soit un coût réel de ${(extractedData.amount - taxReduction).toFixed(2)} € après réduction fiscale.</p>
    </div>

    <!-- Legal Notice -->
    <div class="legal">
      <h4>Mentions Légales</h4>
      <p>
        Ce reçu fiscal est délivré conformément aux dispositions de l'article 200 du Code Général des Impôts.
        Il atteste du versement d'un don au profit de l'Association des Sapeurs-Pompiers de Clermont,
        organisme d'intérêt général habilité à recevoir des dons ouvrant droit à réduction d'impôt.
      </p>
      <p>
        <strong>Important :</strong> Conservez ce reçu précieusement. Il vous sera demandé par l'administration fiscale
        en cas de contrôle. Ce document ne peut être remplacé qu'en cas de perte justifiée.
      </p>
      <p>
        En application de l'article 238 bis du Code Général des Impôts, si vous bénéficiez d'une contrepartie
        en échange de votre don (bien, service, avantage), seule la fraction du versement excédant la valeur
        de cette contrepartie ouvre droit à réduction d'impôt.
      </p>
    </div>

    <!-- Signature -->
    <div class="signature-section">
      <p style="margin-bottom: 10px;">Fait à Clermont,</p>
      <p>Le ${formattedDate}</p>
      <div class="signature-line">
        Le Président de l'Association
      </div>
    </div>

    <!-- Footer -->
    <div class="footer">
      <p><strong>Association des Sapeurs-Pompiers de Clermont</strong></p>
      <p>Document généré automatiquement le ${new Date().toLocaleDateString('fr-FR')} à ${new Date().toLocaleTimeString('fr-FR')}</p>
      <p>Pour toute question : contact@sapeurs-pompiers-clermont.fr</p>
    </div>
  </div>
</body>
</html>`;

return {
  html,
  transaction: extractedData,
  taxReduction,
  formattedDate
};
